module top_module(
    adder,
    address,
    rst,
    clk,
);input clk;
input rst;
input [15:0] adder;
output [7:0] address;
reg   [15:0] obf_count;
assign address[7:0] = obf_count[15:8];
always @(posedge clk or posedge rst) begin
    if (rst) begin
        obf_count <= 0;
    end
    else
    begin
        obf_count <= obf_count + adder;    
    end
end
endmodule
